// Colors below were migrated from saved paint into code via api.paint.*
// (the model is now self-colouring; see /ai/colors.md). Edit colours here.
const __pwModel = (() => {
// Rocket Ship — a retro toy rocket. Parametric & colorable.
//
//   body   : cylindrical fuselage
//   nose   : conical nose cone on top
//   fins    : N tail fins around the base (one shared label -> one color)
//   window : round porthole on the body (toggle)
//   exhaust: flared nozzle at the bottom
//
// Knobs are exposed via api.params(...) -> live Parameters panel.
//
// --- Toy-safety pass -------------------------------------------------------
// Three prints-unsafe spots get fixed here (see /ai/deform.md for api.round /
// api.smoothWeld):
//   1. the nose's needle tip -> api.round(nose, {mode:'convex'}) in isolation
//      (blunts just that cone, before it touches anything else).
//   2. the hard ring crease where the nose meets the body, and
//   3. the razor butt-joint where each fin meets the body
//   -> both are CONCAVE creases, so api.round(..., {mode:'concave'}) fixes
//      them by filling the notch without touching any convex silhouette
//      (the tip, the fins' swept points, panel edges all stay crisp). Using
//      mode:'both' or api.smoothWeld's smin here was tried first and both
//      catastrophically ate the fins down to slivers — the fin profile has
//      two ~33 degree acute corners, so ANY convex-eroding op (opening, or a
//      smin blend across the whole tall assembly) treats most of the blade
//      as "thinner than 2*radius" and rounds it away. concave-only rounding
//      doesn't erode convex material at all, so it's the safe tool here.
// round() remeshes and drops labels, so the body+nose+fins core is built and
// rounded FIRST, unlabeled, and recolored afterward with geometric
// api.paint.* descriptors (slab/cylinder) instead of api.label. The nozzle
// and window pieces are added *after* the rounding passes (never remeshed),
// so they keep the original api.label + api.paint.label coloring untouched.
//
// (Bug fix folded in: the fin's `.extrude(finThick, 0, 0, 0, true)` passed
// scaleTop=0, which per Manifold's extrude() tapers the extrusion to a
// single vertex — i.e. every fin was secretly a knife-edged wedge, not a
// uniform-thickness blade. Invisible in a plain silhouette render, but it's
// exactly why any rounding pass on the original geometry collapsed the fins:
// their true local thickness was near zero almost everywhere. Fixed to
// scaleTop=1 so the fin is a proper finThick-uniform prism.)

const { Manifold, CrossSection } = api;

const p = api.params({
  bodyRadius: { type: 'number', default: 14, min: 8, max: 24, step: 0.5, unit: 'mm', label: 'Body radius' },
  bodyHeight: { type: 'number', default: 46, min: 24, max: 80, step: 1, unit: 'mm', label: 'Body height' },
  noseHeight: { type: 'number', default: 26, min: 10, max: 50, step: 1, unit: 'mm', label: 'Nose height' },
  finCount: { type: 'int', default: 4, min: 0, max: 8, label: 'Fin count' },
  finSweep: { type: 'number', default: 16, min: 6, max: 30, step: 0.5, unit: 'mm', label: 'Fin reach' },
  window: { type: 'boolean', default: true, label: 'Porthole window' },
  windowSize: { type: 'number', default: 6, min: 3, max: 11, step: 0.5, unit: 'mm', label: 'Window radius' },
});

const R = p.bodyRadius;
const clamp = (v, lo, hi) => Math.max(lo, Math.min(hi, v));

// --- Body: cylinder, base at z=0 -------------------------------------------
const body = Manifold.cylinder(p.bodyHeight, R, R);

// --- Nose: cone sitting on top of the body, overlapping by 1mm to fuse -----
const OVERLAP = 1;
const nose = Manifold.cylinder(p.noseHeight + OVERLAP, R, 0)
  .translate([0, 0, p.bodyHeight - OVERLAP]);

// 1) Blunt the needle tip in isolation (convex-only: nose has no concave
// features of its own, so this is cheaper and just as good as mode:'both').
const tipRadius = clamp(R * 0.16, 1.2, 3.5);
const roundedNose = api.round(nose, { radius: tipRadius, mode: 'convex' });

// 2) Smooth the nose/body seam — a concave ring crease — on the small
// body+nose domain (before fins exist, so the fillet lattice doesn't have to
// span the whole tall+wide assembly).
const seamRadius = clamp(R * 0.2, 2, 4.5);
let core = api.round(
  api.expectUnion([body, roundedNose], { expectComponents: 1 }),
  { radius: seamRadius, mode: 'concave' },
);

// --- Exhaust nozzle: flared truncated cone hanging below the base ----------
// Narrow throat where it meets the body, flaring out toward the bottom.
const nozzleH = R * 0.9;
const throatR = R * 0.62;
const bellR = R * 0.92;
// Build it base-up then flip so the wide bell points down (-Z).
const nozzle = api.label(
  Manifold.cylinder(nozzleH + OVERLAP, throatR, bellR)
    .rotate([180, 0, 0]) // flip: wide end now at -Z
    .translate([0, 0, OVERLAP]), // throat overlaps into the body
  'exhaust',
);

// --- Fins: a swept triangular fin, patterned around the base --------------
// Profile in the X(radial)/Z(height) plane, extruded thin along Y, then
// stood up against the body. The fin hugs the body for ~40% of its height
// and sweeps out + down past the base for that classic tail-fin look.
const finBase = p.bodyHeight * 0.42; // how far up the body the fin reaches
const finDrop = R * 0.55; // how far below the base it dips
const finThick = Math.max(2, R * 0.22);
const reach = p.finSweep; // outward sweep distance
const finProfile = CrossSection.ofPolygons([
  [
    [R - 1.2, finBase], // top, tucked into the body
    [R - 1.2, 0], // bottom-inner at the base
    [R + reach, -finDrop], // outer tip, swept down & out
  ]
]);
const fin = finProfile
  .extrude(finThick, 0, 0, 1, true) // centered in Y, UNIFORM thickness finThick (scaleTop=1 — see note above)
  .rotate([90, 0, 0]); // stand the profile up (XY->XZ)

if (p.finCount > 0) {
  const finsAll = api.circularPattern(fin, p.finCount, { axis: 'z' });
  const assembled = api.expectUnion([core, finsAll], { expectComponents: 1 });
  // 3) Smooth the fin/body butt joints — also a concave crease, so this
  // stays convex-safe (fin tips + panel edges are untouched) even though it
  // now runs over the full body+nose+fins domain.
  const finRootRadius = clamp(finThick * 0.49, 1.2, 2.5);
  core = api.round(assembled, { radius: finRootRadius, mode: 'concave' });
}

let rocket = api.expectUnion([core, nozzle], { expectComponents: 1 });

// --- Paint the smoothed core geometrically ----------------------------------
// The round() passes above remeshed body+nose(+fins) into one unlabeled
// surface, so color it back in with region descriptors instead of api.label.
// Order matters: later calls win on overlap, so paint body first, then nose
// (to win the upper band), then fins last (to win the protruding panels
// without touching the plain cylinder wall between them).
const bodyColor = [0.9333333333333333, 0.9490196078431372, 0.9607843137254902];
const noseColor = [0.8862745098039215, 0.23137254901960785, 0.23137254901960785];
const finColor = [0.23137254901960785, 0.43529411764705883, 0.8862745098039215];
const windowColor = [0.35294117647058826, 0.8196078431372549, 0.9019607843137255];
const exhaustColor = [0.9607843137254902, 0.6509803921568628, 0.13725490196078433];

api.paint.slab({ axis: 'z', offset: -2, thickness: p.bodyHeight + 6, color: bodyColor });
api.paint.slab({
  axis: 'z',
  offset: p.bodyHeight - seamRadius,
  thickness: p.noseHeight + seamRadius + OVERLAP + 4,
  color: noseColor,
});
if (p.finCount > 0) {
  // Annular shell just outside the body wall: catches only the swept fin
  // panels (which protrude past R), not the plain cylinder between them.
  api.paint.cylinder({
    center: [0, 0],
    rMin: R + 0.4,
    rMax: R + reach + 2,
    zMin: -finDrop - 2,
    zMax: finBase + 2,
    color: finColor,
  });
}

// --- Porthole window: a framed glass disc on the body's +Y side -----------
// Centered ~62% up the body, facing +Y. No subtraction (which would tunnel
// the wall and split the solid) — instead we ADD two overlapping pucks:
//   * a frame ring (stays "body") standing a touch proud of the surface, and
//   * a glass disc ("window") seated inside it, sunk deep enough to overlap
//     the body wall so the whole thing fuses into one solid.
// Added after the rounding passes, so plain api.label still works here.
if (p.window) {
  const winR = Math.min(p.windowSize, R - 2); // keep a body-frame margin
  const winZ = p.bodyHeight * 0.62;
  const frameW = 1.6; // ring wall thickness
  const proud = 1.4; // how far the frame stands out
  const sink = 3; // how deep pucks reach inward
  const at = (puck) => puck.rotate([-90, 0, 0]).translate([0, R - sink, winZ]);
  // Frame ring: outer disc minus inner disc, both axis-aligned to +Y. The
  // inner bore is cut 0.4 *under* winR so the glass below overlaps the ring
  // wall volumetrically instead of sharing a coincident face (a coincident
  // wall leaves a zero-thickness shard that splits the solid at large R).
  const ring = api.label(
    at(Manifold.cylinder(sink + proud, winR + frameW, winR + frameW)
      .subtract(Manifold.cylinder(sink + proud + 2, winR - 0.4, winR - 0.4).translate([0, 0, -1]))),
    'body',
  );
  // Glass disc: fills the ring (overlapping its bore by 0.4) and reaches
  // `sink` into the wall so the whole porthole fuses into one solid.
  const glass = api.label(
    at(Manifold.cylinder(sink + proud - 0.4, winR, winR)),
    'window',
  );
  rocket = rocket.add(ring).add(glass);
}

return rocket;
})();
api.paint.label("body", [0.9333333333333333, 0.9490196078431372, 0.9607843137254902]);
api.paint.label("window", [0.35294117647058826, 0.8196078431372549, 0.9019607843137255]);
api.paint.label("exhaust", [0.9607843137254902, 0.6509803921568628, 0.13725490196078433]);
return __pwModel;
